<?php $pdo = new PDO("pgsql:host=127.0.0.1;dbname=pc_builder","postgres","postgresql"); $rows=$pdo->query("SELECT name,image_url FROM components ORDER BY category_id,id")->fetchAll(PDO::FETCH_ASSOC); $mh=curl_multi_init(); $handles=[]; foreach($rows as $i=>$r){$ch=curl_init($r["image_url"]); curl_setopt($ch,CURLOPT_NOBODY,true); curl_setopt($ch,CURLOPT_FOLLOWLOCATION,true); curl_setopt($ch,CURLOPT_TIMEOUT,10); curl_setopt($ch,CURLOPT_USERAGENT,"Mozilla/5.0"); $handles[$i]=["ch"=>$ch,"name"=>$r["name"],"url"=>$r["image_url"]]; curl_multi_add_handle($mh,$ch);} do{curl_multi_exec($mh,$running);}while($running>0); $broken=0; foreach($handles as $h){$code=curl_getinfo($h["ch"],CURLINFO_HTTP_CODE); if($code!==200){echo "BROKEN($code): ".$h["name"]." => ".$h["url"].PHP_EOL; $broken++;} curl_multi_remove_handle($mh,$h["ch"]); curl_close($h["ch"]);} curl_multi_close($mh); echo "Broken: $broken / ".count($rows).PHP_EOL;
